const { WebSocketServer } = require('ws');
const http = require('http');
const ALLOWED = new Set(['https://app.example.com']);
const server = http.createServer();
const wss = new WebSocketServer({
  server,
  verifyClient: (info, done) => {
    const origin = info.req.headers.origin;
    done(ALLOWED.has(origin), 403, 'Forbidden origin');
  }
});
wss.on('connection', (ws, req) => {
  const user = sessionFromCookie(req.headers.cookie);
  ws.send(JSON.stringify(user.privateFeed));
});
server.listen(8080);

const { WebSocketServer } = require('ws');
const wss = new WebSocketServer({ port: 8081 });
wss.on('connection', (ws) => {
  // No auth on upgrade; trust an 'auth' message sent after connect
  ws.on('message', (raw) => {
    const msg = JSON.parse(raw);
    if (msg.type === 'auth') { ws.userId = msg.userId; return; }
    if (msg.type === 'read') { ws.send(getAccount(ws.userId)); }
  });
});

const { WebSocketServer } = require('ws');
const jwt = require('jsonwebtoken');
const http = require('http');
const server = http.createServer();
const wss = new WebSocketServer({
  server,
  verifyClient: (info, done) => {
    const proto = info.req.headers['sec-websocket-protocol'];
    try {
      info.req.user = jwt.verify(proto, process.env.WS_SIGNING_KEY, { maxAge: '10m' });
      done(true);
    } catch { done(false, 401, 'Unauthorized'); }
  }
});
wss.on('connection', (ws, req) => { ws.userId = req.user.sub; });
server.listen(8082);

const { WebSocketServer } = require('ws');
const wss = new WebSocketServer({ port: 8083 });
wss.on('connection', (ws) => {
  ws.on('message', (raw) => {
    const { text } = JSON.parse(raw);
    // Re-broadcast raw text; clients do chatDiv.innerHTML += text
    for (const c of wss.clients) c.send(JSON.stringify({ html: text }));
  });
});

const { WebSocketServer } = require('ws');
const wss = new WebSocketServer({ port: 8084 });
const esc = (s) => String(s).replace(/[&<>"']/g, (c) => ({ '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;' }[c]));
wss.on('connection', (ws) => {
  ws.on('message', (raw) => {
    const { text } = JSON.parse(raw);
    if (typeof text !== 'string' || text.length > 2000) return;
    const safe = esc(text);
    for (const c of wss.clients) c.send(JSON.stringify({ text: safe }));
  });
});
